 79→    let (workspace, repo) = common::load_repo(&args.repo)?;
 80→    let commit_ids = common::resolve_revset(&workspace, &repo, &resolved.revset)?;
 81→
 82→    if commit_ids.is_empty() {
 83→        return Err(format!("no commit found for revision '{}'", resolved.revset).into());
 84→    }
 85→
 86→    let root_commit_id = repo.store().root_commit_id().clone();
 87→
 88→    // Resolve the primary commit ID for highlighting
 89→    let primary_ids = common::resolve_revset(&workspace, &repo, &resolved.primary_rev)?;
 90→    let primary_id = primary_ids.first();
 91→
 92→    if let Some(both_count) = resolved.both_count {
 93→        show_both(
 94→            &workspace,
 95→            &repo,
 96→            args,
 97→            both_count,
 98→            file_limit,
 99→            &root_commit_id,
100→        )?;
101→        return Ok(());
102→    }
103→
104→    let mut count = 0;
105→    let mut first = true;
106→    for commit_id in &commit_ids {
107→        if *commit_id == root_commit_id {
108→            continue;
109→        }
110→
111→        if !first {
112→            // Separator between commits
113→            println!("────────────────────────────────────────");
114→        }
115→        first = false;
116→
117→        let commit = repo.store().get_commit(commit_id)?;
118→        let is_primary = primary_id == Some(commit_id);
119→
120→        show_one_commit(&commit, &workspace, &repo, file_limit, is_primary)?;
121→
122→        count += 1;
123→        if let Some(limit) = resolved.limit
124→            && count >= limit
