382→fn print_diff(
383→    commit: &Commit,
384→    repo: &Arc<ReadonlyRepo>,
385→    file_limit: FileLimit,
386→) -> Result<(), Box<dyn std::error::Error>> {
387→    let parent_tree = commit.parent_tree(repo.as_ref()).block_on()?;
388→    let commit_tree = commit.tree();
389→
390→    let diff_iter = TreeDiffIterator::new(&parent_tree, &commit_tree, &EverythingMatcher);
391→
392→    let mut lines: Vec<String> = Vec::new();
393→    for entry in diff_iter {
394→        let diff = entry.values?;
395→        let before = diff.before.as_resolved().cloned().flatten();
396→        let after = diff.after.as_resolved().cloned().flatten();
397→
398→        if matches!(&before, Some(TreeValue::Tree(_))) || matches!(&after, Some(TreeValue::Tree(_)))
399→        {
400→            continue;
401→        }
402→
403→        let path_str = entry.path.as_internal_file_string().to_string();
404→
405→        let line = match (before, after) {
406→            (None, Some(value)) => {
407→                format!("    Added {} {path_str}", file_type_str(&value))
408→            }
409→            (Some(_), None) => {
410→                format!(
411→                    "    Removed {} {path_str}",
412→                    file_type_str_from_merged(&diff.before),
413→                )
414→            }
415→            (Some(_), Some(value)) => {
416→                format!("    Modified {} {path_str}", file_type_str(&value))
417→            }
418→            (None, None) => continue,
419→        };
420→        lines.push(line);
421→    }
422→
423→    let total = lines.len();
424→    let cap = match file_limit {
425→        FileLimit::All | FileLimit::None => 0,
426→        FileLimit::Cap(n) => n,
427→    };
428→    let show_all = cap == 0 || total <= cap;
429→
430→    if show_all {
431→        println!("Changed files: {total}");
432→        for line in &lines {
433→            println!("{line}");
434→        }
435→    } else {
436→        let half = cap / 2;
437→        let tail_start = total.saturating_sub(half);
438→        let skipped = total - half - half;
439→        println!("Changed files: {total} (showing {cap})");
440→        for line in &lines[..half] {
441→            println!("{line}");
442→        }
443→        println!("    ... {skipped} more ...");
444→        for line in &lines[tail_start..] {
445→            println!("{line}");
446→        }
447→    }
448→
449→    Ok(())
450→}
