452→fn file_type_str(value: &TreeValue) -> &'static str {
453→    match value {
454→        TreeValue::File {
455→            executable: false, ..
456→        } => "regular file",
457→        TreeValue::File {
458→            executable: true, ..
459→        } => "executable file",
460→        TreeValue::Symlink(_) => "symlink",
461→        TreeValue::Tree(_) => "tree",
462→        TreeValue::GitSubmodule(_) => "git submodule",
463→    }
464→}
