275→/// Collect formatted lines for `..x..` (both directions).
276→///
277→/// `formatter` converts a `Commit` into a display string.
278→/// Returns `(lines, anchor_index)` — the lines in display order
279→/// (descendants newest first, anchor, ancestors newest first)
280→/// and the index of the anchor commit within the lines.
281→pub fn collect_both<F>(
282→    repo: &Arc<ReadonlyRepo>,
283→    repo_path: &Path,
284→    pos_rev: Option<&str>,
285→    both_count: usize,
286→    formatter: F,
287→) -> Result<(Vec<String>, usize), Box<dyn std::error::Error>>
288→where
289→    F: Fn(&Commit) -> String,
290→{
291→    let bare_rev = pos_rev.unwrap_or("@");
292→    let spec = parse_dot_rev(bare_rev);
293→    let (workspace, _) = load_repo(repo_path)?;
294→    let anchor_ids = resolve_revset(&workspace, repo, &spec.rev)?;
295→    if anchor_ids.is_empty() {
296→        return Err(format!("no commit found for revision '{}'", spec.rev).into());
297→    }
298→    let anchor_id = &anchor_ids[0];
299→    let root_commit_id = repo.store().root_commit_id().clone();
300→

300→
301→    let ancestor_ids = resolve_revset(&workspace, repo, &format!("::{}", spec.rev))?;
302→    let descendant_ids = resolve_revset(&workspace, repo, &format!("{}::", spec.rev))?;
303→
304→    // Descendants (newest first from jj), excluding anchor
305→    let mut desc_lines: Vec<String> = Vec::new();
306→    for commit_id in &descendant_ids {
307→        if *commit_id == root_commit_id || *commit_id == *anchor_id {
308→            continue;
309→        }
310→        let commit = repo.store().get_commit(commit_id)?;
311→        desc_lines.push(formatter(&commit));
312→    }
313→    if both_count > 0 {
314→        let start = desc_lines.len().saturating_sub(both_count);
315→        desc_lines = desc_lines[start..].to_vec();
316→    } else {
317→        desc_lines.clear();
318→    }
319→
320→    // Anchor
321→    let anchor_commit = repo.store().get_commit(anchor_id)?;
322→
323→    // Ancestors (newest first from jj), excluding anchor
324→    let mut anc_lines: Vec<String> = Vec::new();
325→    if both_count > 0 {
326→        let mut count = 0;
327→        for commit_id in &ancestor_ids {
328→            if root_commit_id == *commit_id || *commit_id == *anchor_id {
329→                continue;
330→            }
331→            let commit = repo.store().get_commit(commit_id)?;
332→            anc_lines.push(formatter(&commit));
333→            count += 1;
334→            if count >= both_count {
335→                break;
336→            }
337→        }
338→    }
339→
340→    let anchor_index = desc_lines.len();
341→    let mut result = desc_lines;
342→    result.push(formatter(&anchor_commit));
343→    result.extend(anc_lines);
344→    Ok((result, anchor_index))
345→}
