361→/// Parse and evaluate a revset string, returning commit IDs.
362→pub fn resolve_revset(
363→    workspace: &Workspace,
364→    repo: &Arc<ReadonlyRepo>,
365→    revset_str: &str,
366→) -> Result<Vec<CommitId>, Box<dyn std::error::Error>> {
367→    let aliases_map = RevsetAliasesMap::new();
368→    let fileset_aliases_map = FilesetAliasesMap::new();
369→    let extensions = RevsetExtensions::default();
370→    let workspace_root = workspace.workspace_root().to_path_buf();
371→    let path_converter = RepoPathUiConverter::Fs {
372→        cwd: workspace_root.clone(),
373→        base: workspace_root,
374→    };
375→    let workspace_name = workspace.workspace_name();
376→    let workspace_ctx = RevsetWorkspaceContext {
377→        path_converter: &path_converter,
378→        workspace_name,
379→    };
380→    let context = RevsetParseContext {
381→        aliases_map: &aliases_map,
382→        local_variables: HashMap::new(),
383→        user_email: "",
384→        date_pattern_context: chrono::Utc::now().fixed_offset().into(),
385→        default_ignored_remote: None,
386→        fileset_aliases_map: &fileset_aliases_map,
387→        use_glob_by_default: false,
388→        extensions: &extensions,
389→        workspace: Some(workspace_ctx),
390→    };
391→
392→    let mut diagnostics = RevsetDiagnostics::new();
393→    let expression = jj_lib::revset::parse(&mut diagnostics, revset_str, &context)?;
394→
395→    let no_extensions: &[Box<dyn jj_lib::revset::SymbolResolverExtension>] = &[];
396→    let symbol_resolver = SymbolResolver::new(repo.as_ref(), no_extensions);
397→    let resolved = expression.resolve_user_expression(repo.as_ref(), &symbol_resolver)?;
398→    let revset = resolved.evaluate(repo.as_ref())?;
399→
400→    let mut commit_ids = Vec::new();
401→    for result in revset.iter() {
402→        commit_ids.push(result?);
403→    }
404→    Ok(commit_ids)
405→}
